texttool_globals_notification_message___sharing_pw_required = TextObject(bs_BA="Unesite lozinku za aktiviranje da bi pokrenuli vozilo.", cs_CZ="Zadejte prosím své aktivační heslo ke startování vozidla.", da_DK="Angiv dit aktiveringspassword for at starte bilen.", de_DE="Bitte gib dein Aktivierungspasswort ein, um das Fahrzeug\nzu starten.", el_GR="Καταχωρίστε τον κωδικό πρόσβασης ενεργοποίησής σας, για να\nεκκινήσετε το όχημα.", en_GB="Please enter your activation password to start the vehicle.", es_ES="Por favor, introduzca su contraseña de activación para arrancar el\nvehículo.", fi_FI="Syötä aktivointisalasana auton käynnistystä varten.", fr_FR="Veuillez entrer votre mot de passe d'activation pour démarrer le\nvéhicule.", hr_HR="Unesite svoju lozinku za aktiviranje kako biste pokrenuli vozilo.", hu_HU="A jármű elindításához add meg az aktiválási jelszavad.", it_IT="Immettere la password di attivazione per avviare la vettura.", nl_NL="Voer alsjeblieft je activeringswachtwoord in om het voertuig te\nstarten.", no_NO="Legg inn aktiveringspassordet for å starte bilen.", pl_PL="Proszę wprowadzić hasło aktywacyjne, aby uruchomić pojazd.", pt_PT="Por favor, introduz a tua palavra-passe de ativação para ligar o\nveículo.", ro_RO="Introduceţi parola dumneavoastră de activare, pentru a porni\nautovehiculul.", ru_RU="Пожалуйста, введите пароль активации, чтобы завести\nавтомобиль.", sk_SK="Aby ste naštartovali vozidlo, zadajte svoje aktivačné heslo.", sl_SI="Za zagon vozila vnesite svoje geslo za aktivacijo.", sr_RS="Unesite lozinku za aktiviranje da bi pokrenuli vozilo.", sv_SE="Ange aktiveringslösenordet för att starta bilen.", tr_TR="Aracı başlatmak için, lütfen aktivasyon şifreni gir.", uk_UA="Будь ласка, введіть пароль активації, щоб завести автомобіль.")
